    sh:result [ a sh:ValidationResult ;
            sh:focusNode _:N9b30076d8aa04ca4923b19b3adaf7a4e ;
            sh:resultMessage "A CDIF codelist concept must have a resolvable IRI as @id." ;
            sh:resultSeverity sh:Violation ;
